     1	import { useMemo, useState } from 'react';
     2	import { Link, useNavigate } from 'react-router-dom';
     3	import { useModelIndex, useModelStore, useModelDelete } from '@rhino-dev/rhino-react';
     4	import type { Blog } from '../types';
     5	import { Icon } from '../components/Icons';
     6	import { useToast } from '../components/Toaster';
     7	import { fmtRelative } from '../lib/format';
     8	import { Loading } from './DashboardPage';
     9	
    10	const PER_PAGE = 10;
    11	type Sort = '-id' | 'title' | '-title' | 'created_at' | '-created_at';
    12	
    13	export function BlogsPage() {
    14	  const nav = useNavigate();
    15	  const toast = useToast();
    16	  const [search, setSearch] = useState('');
    17	  const [publishedFilter, setPublishedFilter] = useState('');
    18	  const [sort, setSort] = useState<Sort>('-created_at');
    19	  const [page, setPage] = useState(1);
    20	  const [showNew, setShowNew] = useState(false);
    21	
    22	  const filters = useMemo(() => {
    23	    const f: Record<string, any> = {};
    24	    if (publishedFilter === 'true') f.published = true;
    25	    if (publishedFilter === 'false') f.published = false;
    26	    return f;
    27	  }, [publishedFilter]);
    28	
    29	  const blogs = useModelIndex<Blog>('blogs', {
    30	    filters,
    31	    search: search || undefined,
    32	    sort,
    33	    page,
    34	    perPage: PER_PAGE,
    35	  });
    36	
    37	  const store = useModelStore<Blog>('blogs');
    38	  const del = useModelDelete<Blog>('blogs');
    39	
    40	  const list = blogs.data?.data ?? [];
    41	  const pag = blogs.data?.pagination;
    42	
    43	  function onSortClick(field: Exclude<Sort, `-${string}`>) {
    44	    setSort(s => (s === field ? (`-${field}` as Sort) : field));
    45	  }
    46	
    47	  return (
    48	    <>
    49	      <div className="page-head">
    50	        <div>
    51	          <h1 className="page-title">Blogs</h1>
    52	          <p className="page-sub">Multi-tenant scope: <span className="mono accent">/api/{`{org}`}/blogs</span></p>
    53	        </div>
    54	        <button className="btn btn-primary" onClick={() => setShowNew(true)}>
    55	          <Icon.plus size={14} /> New blog
    56	        </button>
    57	      </div>
    58	
    59	      <div className="toolbar">
    60	        <input
    61	          className="input input-search"
    62	          style={{ flex: 1, maxWidth: 320 }}
    63	          placeholder="Search title / body…"
    64	          value={search}
    65	          onChange={e => { setPage(1); setSearch(e.target.value); }}
    66	        />
    67	        <select
    68	          className="input select"
    69	          value={publishedFilter}
    70	          onChange={e => { setPage(1); setPublishedFilter(e.target.value); }}
    71	        >
    72	          <option value="">All status</option>
    73	          <option value="true">Published</option>
    74	          <option value="false">Draft</option>
    75	        </select>
    76	        <span className="faint" style={{ marginLeft: 'auto', fontSize: 12 }}>
    77	          {blogs.isFetching ? 'fetching…' : `${list.length} of ${pag?.total ?? list.length}`}
    78	        </span>
    79	      </div>
    80	
    81	      <div className="card" style={{ overflow: 'visible' }}>
    82	        {blogs.isLoading ? <Loading /> : list.length === 0 ? (
    83	          <div className="empty">
    84	            <h3>No blogs match</h3>
    85	            <p>Try a different filter, or create one.</p>
    86	          </div>
    87	        ) : (
    88	          <table className="table">
    89	            <thead>
    90	              <tr>
    91	                <Th label="Title" field="title" sort={sort} onClick={onSortClick} />
    92	                <th>Status</th>
    93	                <Th label="Created" field="created_at" sort={sort} onClick={onSortClick} />
    94	                <th style={{ width: 60 }}></th>
    95	              </tr>
    96	            </thead>
    97	            <tbody>
    98	              {list.map(b => (
    99	                <tr key={b.id} onClick={() => nav(`/blogs/${b.id}`)}>
   100	                  <td>
   101	                    <Link to={`/blogs/${b.id}`} onClick={e => e.stopPropagation()} style={{ fontWeight: 600 }}>
   102	                      {b.title || 'Untitled'}
   103	                    </Link>
   104	                    <div className="faint" style={{ fontSize: 11, marginTop: 2 }}>
   105	                      {b.body?.slice(0, 90)}
   106	                      {b.body && b.body.length > 90 ? '...' : ''}
   107	                    </div>
   108	                  </td>
   109	                  <td>
   110	                    <span className={`pill ${b.published ? 'pill-active' : 'pill-draft'}`}>
   111	                      {b.published ? 'Published' : 'Draft'}
   112	                    </span>
   113	                  </td>
   114	                  <td className="faint">{fmtRelative(b.created_at)}</td>
   115	                  <td>
   116	                    <button
   117	                      className="btn btn-ghost btn-icon"
   118	                      title="Soft delete (move to trash)"
   119	                      onClick={async e => {
   120	                        e.stopPropagation();
   121	                        if (!confirm(`Delete blog "${b.title || 'Untitled'}"?`)) return;
   122	                        try {
   123	                          await del.mutateAsync(b.id);
   124	                          toast(`Deleted "${b.title || 'Untitled'}"`, 'ok');
   125	                        } catch (err) {
   126	                          toast(`Delete failed: ${(err as Error).message}`, 'error');
   127	                        }
   128	                      }}
   129	                    >
   130	                      <Icon.trash size={14} />
   131	                    </button>
   132	                  </td>
   133	                </tr>
   134	              ))}
   135	            </tbody>
   136	          </table>
   137	        )}
   138	
   139	        {pag && pag.lastPage > 1 && (
   140	          <div className="pager">
   141	            <div className="pager-info">Page {pag.currentPage} of {pag.lastPage} · {pag.total} total</div>
   142	            <div className="pager-ctrls">
   143	              <button className="btn btn-sm" disabled={page <= 1} onClick={() => setPage(p => p - 1)}>
   144	                <Icon.arrowL size={12} />
   145	              </button>
   146	              <button className="btn btn-sm" disabled={page >= pag.lastPage} onClick={() => setPage(p => p + 1)}>
   147	                <Icon.arrowR size={12} />
   148	              </button>
   149	            </div>
   150	          </div>
   151	        )}
   152	      </div>
   153	
   154	      {showNew && (
   155	        <NewBlogModal
   156	          onClose={() => setShowNew(false)}
   157	          onCreate={async data => {
   158	            try {
   159	              const created = await store.mutateAsync(data);
   160	              toast(`Created "${created.title || 'Untitled'}"`, 'ok');
   161	              setShowNew(false);
   162	            } catch (err) {
   163	              toast(`Create failed: ${(err as Error).message}`, 'error');
   164	            }
   165	          }}
   166	          busy={store.isPending}
   167	        />
   168	      )}
   169	    </>
   170	  );
   171	}
   172	
   173	function Th(props: { label: string; field: string | null; sort?: string; onClick?: (f: any) => void }) {
   174	  const { label, field, sort, onClick } = props;
   175	  if (!field || !onClick) return <th>{label}</th>;
   176	  const active = sort === field || sort === `-${field}`;
   177	  return (
   178	    <th className={active ? 'sorted' : ''} onClick={() => onClick(field)}>
   179	      {label}
   180	      <span className="sort-arrow">{active ? (sort === field ? '↑' : '↓') : '↕'}</span>
   181	    </th>
   182	  );
   183	}
   184	
   185	function NewBlogModal({ onClose, onCreate, busy }: { onClose: () => void; onCreate: (data: Partial<Blog>) => Promise<void>; busy: boolean }) {
   186	  const [title, setTitle] = useState('');
   187	  const [body, setBody] = useState('');
   188	  const [published, setPublished] = useState(false);
   189	
   190	  return (
   191	    <div className="modal-backdrop" onClick={onClose}>
   192	      <div className="modal" onClick={e => e.stopPropagation()}>
   193	        <div className="modal-head">
   194	          <div className="modal-title">New blog</div>
   195	          <button className="btn btn-ghost btn-icon" onClick={onClose}><Icon.close /></button>
   196	        </div>
   197	        <div className="modal-body">
   198	          <form className="form" onSubmit={e => { e.preventDefault(); onCreate({ title, body, published }); }}>
   199	            <div className="field">
   200	              <label>Title</label>
   201	              <input className="input" value={title} onChange={e => setTitle(e.target.value)} required autoFocus />
   202	            </div>
   203	            <div className="field">
   204	              <label>Body</label>
   205	              <textarea className="input" rows={6} value={body} onChange={e => setBody(e.target.value)} required />
   206	            </div>
   207	            <div className="field-row" style={{ display: 'flex', alignItems: 'center', gap: 8, margin: '12px 0' }}>
   208	              <input
   209	                type="checkbox"
   210	                id="published"
   211	                checked={published}
   212	                onChange={e => setPublished(e.target.checked)}
   213	              />
   214	              <label htmlFor="published" style={{ margin: 0, cursor: 'pointer' }}>Publish immediately</label>
   215	            </div>
   216	            <div className="modal-foot" style={{ padding: 0, border: 0 }}>
   217	              <button type="button" className="btn btn-ghost" onClick={onClose}>Cancel</button>
   218	              <button type="submit" className="btn btn-primary" disabled={busy}>
   219	                {busy ? <span className="spinner" /> : <Icon.check size={14} />} Create
   220	              </button>
   221	            </div>
   222	          </form>
   223	        </div>
   224	      </div>
   225	    </div>
   226	  );
   227	}
